28	struct SynthPass : public ScriptPass {
29		SynthPass() : ScriptPass("synth", "generic synthesis script") {}
30	
31		void help() override
32		{
33			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
34			log("\n");
35			log("    synth [options]\n");
36			log("\n");
37			log("This command runs the default synthesis script. This command does not operate\n");
38			log("on partly selected designs.\n");
39			log("\n");
40			log("    -top <module>\n");
41			log("        use the specified module as top module (default='top')\n");
42			log("\n");
43			log("    -auto-top\n");
44			log("        automatically determine the top of the design hierarchy\n");
45			log("\n");
46			log("    -flatten\n");
47			log("        flatten the design before synthesis. this will pass '-auto-top' to\n");
48			log("        'hierarchy' if no top module is specified.\n");
49			log("\n");
50			log("    -hieropt\n");
51			log("        enable hierarchical optimization. this option is useful when `-flatten'\n");
52			log("        is not used, or when selected modules are marked with 'keep_hierarchy'\n.");
53			log("        to prevent their dissolution.\n");
54			log("\n");
55			log("    -encfile <file>\n");
56			log("        passed to 'fsm_recode' via 'fsm'\n");
57			log("\n");
58			log("    -lut <k>\n");
59			log("        perform synthesis for a k-LUT architecture.\n");
60			log("\n");
61			log("    -nofsm\n");
62			log("        do not run FSM optimization\n");
63			log("\n");
64			log("    -noabc\n");
65			log("        do not run abc (as if yosys was compiled without ABC support)\n");
66			log("\n");
67			log("    -booth\n");
68			log("        run the booth pass to map $mul to Booth encoded multipliers\n");
69			log("\n");
70			log("    -arith_tree\n");
71			log("        run the arith_tree pass to convert $add/$sub chains and $macc cells to\n");
72			log("        carry-save adder trees.\n");
73			log("\n");
74			log("    -noalumacc\n");
75			log("        do not run 'alumacc' pass. i.e. keep arithmetic operators in\n");
76			log("        their direct form ($add, $sub, etc.).\n");
77			log("\n");
78			log("    -nordff\n");
79			log("        passed to 'memory'. prohibits merging of FFs into memory read ports\n");
80			log("\n");
81			log("    -latches <auto|warn|error>\n");
82			log("        controls how the inference of a latch is reported.\n");
83			log("\n");
84			log("    -noshare\n");
85			log("        do not run SAT-based resource sharing\n");
86			log("\n");
87			log("    -run <from_label>[:<to_label>]\n");
88			log("        only run the commands between the labels (see below). an empty\n");
89			log("        from label is synonymous to 'begin', and empty to label is\n");
90			log("        synonymous to the end of the command list.\n");
91			log("\n");
92			log("    -abc9\n");
93			log("        use new ABC9 flow (EXPERIMENTAL)\n");
94			log("\n");
95			log("    -flowmap\n");
96			log("        use FlowMap LUT techmapping instead of ABC\n");
97			log("\n");
98			log("    -no-rw-check\n");
99			log("        marks all recognized read ports as \"return don't-care value on\n");
100			log("        read/write collision\" (same result as setting the no_rw_check\n");
101			log("        attribute on all memories).\n");
102			log("\n");
103			log("    -extra-map filename\n");
104			log("        source extra rules from the given file to complement the default\n");
105			log("        mapping library in the `techmap` step. this option can be\n");
106			log("        repeated.\n");
107			log("\n");
108			log("    -relativeshare\n");
109			log("        use paths relative to share directory for source locations\n");
110			log("        where possible (experimental).\n");
111			log("\n");
112			log("The following commands are executed by this synthesis command:\n");
113			help_script();
114			log("\n");
115		}
116	
117		string top_module, fsm_opts, memory_opts, abc, latches_opt;
118		bool autotop, flatten, noalumacc, nofsm, noabc, noshare, flowmap, booth, arith_tree, hieropt, relative_share;
119		int lut;
120		std::vector<std::string> techmap_maps;
121	
122		void clear_flags() override
123		{
124			top_module.clear();
125			fsm_opts.clear();
126			memory_opts.clear();
127			latches_opt.clear();
128	
129			autotop = false;
130			flatten = false;
131			lut = 0;
132			noalumacc = false;
133			nofsm = false;
134			noabc = false;
135			noshare = false;
136			flowmap = false;
137			booth = false;
138			arith_tree = false;
139			hieropt = false;
140			relative_share = false;
141			abc = "abc";
142			techmap_maps.clear();
143		}
144	
145		void execute(std::vector<std::string> args, RTLIL::Design *design) override
146		{
147			string run_from, run_to;
148			clear_flags();
149	
150			size_t argidx;
151			for (argidx = 1; argidx < args.size(); argidx++) {
152				if (args[argidx] == "-top" && argidx + 1 < args.size()) {
153					top_module = args[++argidx];
154					continue;
155				}
156				if (args[argidx] == "-encfile" && argidx + 1 < args.size()) {
157					fsm_opts = " -encfile " + args[++argidx];
158					continue;
159				}
160				if (args[argidx] == "-run" && argidx + 1 < args.size()) {
161					size_t pos = args[argidx + 1].find(':');
162					if (pos == std::string::npos) {
163						run_from = args[++argidx];
164						run_to = args[argidx];
165					} else {
166						run_from = args[++argidx].substr(0, pos);
167						run_to = args[argidx].substr(pos + 1);
168					}
169					continue;
170				}
171				if (args[argidx] == "-auto-top") {
172					autotop = true;
173					continue;
174				}
175				if (args[argidx] == "-flatten") {
176					flatten = true;
177					continue;
178				}
179				if (args[argidx] == "-lut" && argidx + 1 < args.size()) {
180					lut = atoi(args[++argidx].c_str());
181					continue;
182				}
183				if (args[argidx] == "-nofsm") {
184					nofsm = true;
185					continue;
186				}
187				if (args[argidx] == "-noabc") {
188					noabc = true;
189					continue;
190				}
191				if (args[argidx] == "-noalumacc") {
192					noalumacc = true;
193					continue;
194				}
195				if (args[argidx] == "-booth") {
196					booth = true;
197					continue;
198				}
199				if (args[argidx] == "-arith_tree") {
200					arith_tree = true;
201					continue;
202				}
203				if (args[argidx] == "-nordff") {
204					memory_opts += " -nordff";
205					continue;
206				}
207				if (args[argidx] == "-latches" && argidx + 1 < args.size()) {
208					latches_opt += " -latches " + args[++argidx];
209					continue;
210				}
211				if (args[argidx] == "-noshare") {
212					noshare = true;
213					continue;
214				}
215				if (args[argidx] == "-abc9") {
216					abc = "abc9";
217					continue;
218				}
219				if (args[argidx] == "-flowmap") {
220					flowmap = true;
221					continue;
222				}
223				if (args[argidx] == "-no-rw-check") {
224					memory_opts += " -no-rw-check";
225					continue;
226				}
227				if (args[argidx] == "-extra-map" && argidx + 1 < args.size()) {
228					techmap_maps.push_back(args[++argidx]);
229					continue;
230				}
231				if (args[argidx] == "-hieropt") {
232					hieropt = true;
233					continue;
234				}
235				if (args[argidx] == "-relativeshare") {
236					relative_share = true;
237					log_experimental("synth -relativeshare");
238					continue;
239				}
240				break;
241			}
242			extra_args(args, argidx, design);
243	
244			if (!design->full_selection())
245				log_cmd_error("This command only operates on fully selected designs!\n");
246	
247			if (abc == "abc9" && !lut)
248				log_cmd_error("ABC9 flow only supported for FPGA synthesis (using '-lut' option)\n");
249			if (flowmap && !lut)
250				log_cmd_error("FlowMap is only supported for FPGA synthesis (using '-lut' option)\n");
251	
252			log_header(design, "Executing SYNTH pass.\n");
253			log_push();
254	
255			run_script(design, run_from, run_to);
256	
257			log_pop();
258		}
259	
260		void script() override
261		{
262			std::string hieropt_flag;
263			if (help_mode)
264				hieropt_flag = " [-hier]";
265			else
266				hieropt_flag = hieropt ? " -hier" : "";
267	
268			std::string techmap_cmd = "techmap";
269			if (relative_share)
270				techmap_cmd += " -relativeshare";
271	
272			if (check_label("begin")) {
273				if (help_mode) {
274					run("hierarchy -check [-top <top> | -auto-top]");
275				} else {
276					if (top_module.empty()) {
277						if (flatten || autotop)
278							run("hierarchy -check -auto-top");
279						else
280							run("hierarchy -check");
281					} else
282						run(stringf("hierarchy -check -top %s", top_module));
283				}
284			}
285	
286			if (check_label("coarse")) {
287				run("proc" + latches_opt);
288				if (flatten || help_mode) {
289					run("check");
290					run("flatten", "  (if -flatten)");
291				}
292				run("opt_expr");
293				run("opt_clean");
294				run("check");
295				run("opt -nodffe -nosdff");
296				if (!nofsm || help_mode)
297					run("fsm" + fsm_opts, "      (unless -nofsm)");
298				run("opt" + hieropt_flag);
299				run("wreduce");
300				run("peepopt");
301				run("opt_clean");
302				if (help_mode)
303					run(techmap_cmd + " -map +/cmp2lut.v -map +/cmp2lcu.v", " (if -lut)");
304				else if (lut)
305					run(stringf("%s -map +/cmp2lut.v -map +/cmp2lcu.v -D LUT_WIDTH=%d", techmap_cmd, lut));
306				if (booth || help_mode)
307					run("booth", "    (if -booth)");
308				if (!noalumacc)
309					run("alumacc", "  (unless -noalumacc)");
310				if (arith_tree || help_mode)
311					run("arith_tree", " (if -arith_tree)");
312				if (!noshare)
313					run("share", "    (unless -noshare)");
314				run("opt" + hieropt_flag);
315				run("memory -nomap" + memory_opts);
316				run("opt_clean");
317			}
318	
319			if (check_label("fine")) {
320				run("opt -fast -full" + hieropt_flag);
321				run("memory_map");
322				run("opt -full");
323				if (help_mode) {
324					run(techmap_cmd, "                  (unless -extra-map)");
325					run(techmap_cmd + " -map +/techmap.v -map <inject>", "  (if -extra-map)");
326				} else {
327					std::string techmap_opts;
328					if (!techmap_maps.empty())
329						techmap_opts += " -map +/techmap.v";
330					for (auto fn : techmap_maps)
331						techmap_opts += stringf(" -map %s", fn);
332					run(techmap_cmd + techmap_opts);
333				}
334				if (help_mode) {
335					run(techmap_cmd + " -map +/gate2lut.v", "(if -noabc and -lut)");
336					run("clean; opt_lut", "           (if -noabc and -lut)");
337					run("flowmap -maxlut K", "        (if -flowmap and -lut)");
338				} else if (noabc && lut) {
339					run(stringf("%s -map +/gate2lut.v -D LUT_WIDTH=%d", techmap_cmd, lut));
340					run("clean; opt_lut");
341				} else if (flowmap) {
342					run(stringf("flowmap -maxlut %d", lut));
343				}
344				run("opt -fast" + hieropt_flag);
345	
346				if ((!noabc && !flowmap) || help_mode) {
347	#ifdef YOSYS_ENABLE_ABC
348					if (help_mode) {
349						run(abc, "       (unless -noabc, unless -lut)");
350						run(abc + " -lut k", "(unless -noabc, if -lut)");
351					} else {
352						if (lut)
353							run(stringf("%s -lut %d", abc, lut));
354						else
355							run(abc);
356					}
357					run("opt -fast", "       (unless -noabc)");
358	#endif
359				}
360			}
361	
362			if (check_label("check")) {
363				run("hierarchy -check");
364				run("stat");
365				run("check");
366			}
367		}
368	} SynthPass;
369	
370	PRIVATE_NAMESPACE_END
